def range_summary(nums):
    if not nums:
        return ''

    runs = [(nums[0], nums[0])]
    for n in nums[1:]:
        last_run = runs[-1]
        if n == last_run[1] + 1:
            last_run[1] = n
        else:
            runs.append((n, n))

    result = ', '.join(str(start) if start != end else str(start) for start, end in runs)
    return result
